6	export function convertBase64ToUint8Array(base64String: string) {
7	  const base64Url = base64String.replace(/-/g, '+').replace(/_/g, '/');
8	  const latin1string = atob(base64Url);
9	  return Uint8Array.from(latin1string, byte => byte.codePointAt(0)!);
10	}
