12	export function convertUint8ArrayToBase64(array: Uint8Array): string {
13	  let latin1string = '';
14	
15	  // Note: regular for loop to support older JavaScript versions that
16	  // do not support for..of on Uint8Array
17	  for (let i = 0; i < array.length; i++) {
18	    latin1string += String.fromCodePoint(array[i]);
19	  }
20	
21	  return btoa(latin1string);
22	}
