1	import type { ImageModelV3, SharedV3Warning } from '@ai-sdk/provider';
2	import type { InferSchema, Resolvable } from '@ai-sdk/provider-utils';
3	import {
4	  FetchFunction,
5	  combineHeaders,
6	  createBinaryResponseHandler,
