179	export const prodiaImageModelOptionsSchema = lazySchema(() =>
180	  zodSchema(
181	    z.object({
182	      /**
183	       * Amount of computational iterations to run. More is typically higher quality.
184	       */
185	      steps: z.number().int().min(1).max(4).optional(),
186	      /**
187	       * Width of the output image in pixels.
188	       */
189	      width: z.number().int().min(256).max(1920).optional(),
190	      /**
191	       * Height of the output image in pixels.
192	       */
193	      height: z.number().int().min(256).max(1920).optional(),
194	      /**
195	       * Apply a visual theme to your output image.
196	       */
197	      stylePreset: z.enum(stylePresets).optional(),
198	      /**
199	       * Augment the output with a LoRa model.
200	       */
201	      loras: z.array(z.string()).max(3).optional(),
