68	            prompt,
69	            image: await Promise.all(files.map(file => fileToBlob(file))),
70	            mask: mask != null ? await fileToBlob(mask) : undefined,
71	            n,
72	            size,
73	            ...(providerOptions.deepinfra ?? {}),
74	          },
