88	      return {
89	        images: response.data.map(item => item.b64_json),
90	        warnings,
91	        response: {
92	          timestamp: currentDate,
93	          modelId: this.modelId,
94	          headers: responseHeaders,
95	        },
96	      };
97	    }
98	
99	    // Standard image generation mode
