125	    return {
126	      images: response.images.map(image =>
127	        image.replace(/^data:image\/\w+;base64,/, ''),
128	      ),
129	      warnings,
130	      response: {
131	        timestamp: currentDate,
132	        modelId: this.modelId,
133	        headers: responseHeaders,
134	      },
135	    };
